-- Corrected script to update branch_id values for existing subjects\n-- Execute this AFTER running the column addition script\n\n-- Step 1: Check what branches are available (CORRECTED QUERY)\nSELECT 'Available branches:' as info;\nSELECT school_id, branch_id, branch_name, status \nFROM school_locations \nWHERE status = 'Active' \nORDER BY school_id, branch_id;\n\n-- Step 2: Check subjects that need branch_id\nSELECT 'Subjects needing branch_id:' as info;\nSELECT \n    school_id,\n    COUNT(*) as subject_count,\n    GROUP_CONCAT(DISTINCT section) as sections\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = ''\nGROUP BY school_id;\n\n-- Step 3: Generate suggested update statements\nSELECT 'Suggested UPDATE statements:' as info;\nSELECT CONCAT(\n    'UPDATE subjects SET branch_id = \"', \n    branch_mapping.branch_id, \n    '\" WHERE school_id = \"', \n    branch_mapping.school_id, \n    '\" AND (branch_id IS NULL OR branch_id = \"\"); -- ', \n    branch_mapping.branch_name\n) as suggested_update_statement\nFROM (\n    SELECT \n        school_id,\n        MIN(branch_id) as branch_id,\n        MIN(branch_name) as branch_name\n    FROM school_locations \n    WHERE status = 'Active'\n    GROUP BY school_id\n) branch_mapping\nWHERE branch_mapping.school_id IN (\n    SELECT DISTINCT school_id \n    FROM subjects \n    WHERE branch_id IS NULL OR branch_id = ''\n);\n\n-- Step 4: Manual update examples (MODIFY WITH YOUR ACTUAL VALUES)\n-- Copy the suggested statements above or use these examples:\n\n-- Example for SCH/1:\n-- UPDATE subjects SET branch_id = 'BRCH00001' WHERE school_id = 'SCH/1' AND (branch_id IS NULL OR branch_id = '');\n\n-- Example for SCH/2:\n-- UPDATE subjects SET branch_id = 'BRCH00002' WHERE school_id = 'SCH/2' AND (branch_id IS NULL OR branch_id = '');\n\n-- Step 5: Automatic update using first available branch per school\n-- UNCOMMENT THE FOLLOWING IF YOU WANT AUTOMATIC ASSIGNMENT:\n\n/*\nUPDATE subjects s\nSET s.branch_id = (\n    SELECT MIN(sl.branch_id)\n    FROM school_locations sl\n    WHERE sl.school_id = s.school_id\n    AND sl.status = 'Active'\n    LIMIT 1\n)\nWHERE s.branch_id IS NULL OR s.branch_id = '';\n*/\n\n-- Step 6: Verification\nSELECT 'Verification - subjects without branch_id (should be 0):' as check_result;\nSELECT COUNT(*) as subjects_without_branch_id\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 7: Show distribution with branch names\nSELECT 'Subject distribution by school and branch:' as distribution;\nSELECT \n    s.school_id,\n    s.branch_id,\n    sl.branch_name,\n    COUNT(*) as subject_count,\n    GROUP_CONCAT(DISTINCT s.section) as sections\nFROM subjects s\nLEFT JOIN school_locations sl ON s.school_id = sl.school_id AND s.branch_id = sl.branch_id\nWHERE s.branch_id IS NOT NULL AND s.branch_id != ''\nGROUP BY s.school_id, s.branch_id, sl.branch_name\nORDER BY s.school_id, s.branch_id;\n\n-- Step 8: Check for invalid branch_id values\nSELECT 'Subjects with invalid branch_id (should be empty):' as validation;\nSELECT \n    s.school_id,\n    s.branch_id,\n    COUNT(*) as invalid_subjects\nFROM subjects s\nLEFT JOIN school_locations sl ON s.school_id = sl.school_id AND s.branch_id = sl.branch_id\nWHERE s.branch_id IS NOT NULL \nAND s.branch_id != ''\nAND sl.branch_id IS NULL\nGROUP BY s.school_id, s.branch_id;\n\n-- Step 9: Final success check\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN '✅ SUCCESS: All subjects have valid branch_id values!'\n        ELSE CONCAT('❌ ERROR: ', COUNT(*), ' subjects still need branch_id values!')\n    END as migration_status\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 10: Show sample of updated subjects\nSELECT 'Sample of subjects with branch_id (first 10):' as info;\nSELECT \n    s.subject_code,\n    s.subject,\n    s.school_id,\n    s.branch_id,\n    sl.branch_name,\n    s.section,\n    s.class_code,\n    s.status\nFROM subjects s\nLEFT JOIN school_locations sl ON s.school_id = sl.school_id AND s.branch_id = sl.branch_id\nWHERE s.branch_id IS NOT NULL AND s.branch_id != ''\nLIMIT 10;\n"